import torchimport torch.nn as nnimport torch.nn.functional as F# 德国慕尼黑工业大学计算、信息与技术学院# B站：CV缝合救星"""70. Dual-domain strip attention for image restoration (2024 NN 顶刊论文)    双域条带注意力用于图像恢复    即插即用模块：Spatial Strip Attention (SSA) 添花模块    一、背景在图像恢复任务中，传统方法依赖手工特征和假设，在复杂场景下效果欠佳。卷积神经网络（CNNs）虽取得进展，但卷积操作存在静态滤波器适应性差、感受野有限的问题。Transformer 引入自注意力机制虽能建模长距离依赖，但二次复杂度限制其在高分辨率图像恢复中的应用。为解决这些问题，提出空间带状注意力单元（SSA），旨在高效聚合信息，提升图像恢复性能。二、SSA 介绍（一）整体设计SSA 是双域带状注意力机制（DSAM）的重要组成部分，用于在图像恢复网络中增强空间特征表示。它通过在同一行或列的相邻位置为每个像素聚合上下文信息，以低计算成本改进特征表示，进而提升网络对图像中各种细节和结构的捕捉能力，帮助恢复更清晰、准确的图像。（二）核心组件与操作1. 注意力权重生成：摒弃自注意力生成查询（Q）、键（K）、值（V）张量的复杂过程，通过一个极为轻量级的分支直接生成注意力权重。该分支由全局平均池化（GAP）、1×1 卷积和 Sigmoid 函数构成，以此根据输入特征生成自适应的注意力权重，这些权重用于指导后续的信息聚合。2. 信息聚合方式：采用卷积式的聚合方法，利用生成的注意力权重对相邻位置的特征进行加权求和，从而得到精炼后的特征。这种聚合方式使得每个像素能融合来自相邻区域的信息，丰富了像素的特征表示，有助于网络更好地理解图像的局部结构。3. 扩大感受野策略：为进一步增强上下文信息的捕捉能力，SSA 通过依次应用水平和垂直带状注意力算子，让每个像素能够感知以自身为中心的更大区域内的信息，隐式地扩大了网络的感受野，提升对图像全局结构的把握能力。三、微观设计考量SSA 通过简化注意力权重生成过程和采用低复杂度的聚合方式，有效降低了计算成本。同时，其独特的水平和垂直注意力结合方式，在不显著增加计算量的情况下，显著扩大了感受野，增强了模型对图像全局和局部特征的捕捉能力。消融实验验证了 SSA 各组件的有效性，表明其对提升图像恢复性能起到关键作用，在计算效率和特征捕捉能力的平衡上表现出色。 四、适用任务1. SSA 主要应用于图像恢复任务，包括图像去雾、去雪、去噪和去模糊等。在这些任务中，SSA 能够帮助网络更好地捕捉图像中的有效信息，去除各种退化因素的影响，恢复出高质量的图像。例如在去雾任务中，SSA 可以有效聚合上下文信息，更精准地识别和去除雾气，使恢复后的图像更清晰；在去噪任务中，能更好地保留图像细节，同时去除噪声干扰。2. 适用于所有分类、分割、检测等所有CV任务。"""class SSA(nn.Module):    def __init__(self, dim, group, kernel) -> None:        super().__init__()        self.H_spatial_att = spatial_strip_att_unit(dim, group=group, kernel=kernel)        self.W_spatial_att = spatial_strip_att_unit(dim, group=group, kernel=kernel, H=False)        self.gamma = nn.Parameter(torch.zeros(dim, 1, 1))        self.beta = nn.Parameter(torch.ones(dim, 1, 1))    def forward(self, x):        out = self.H_spatial_att(x)        out = self.W_spatial_att(out)        return self.gamma * out + x * self.betaclass spatial_strip_att_unit(nn.Module):    def __init__(self, dim, kernel=5, group=2, H=True) -> None:        super().__init__()        self.k = kernel        pad = kernel // 2        self.kernel = (1, kernel) if H else (kernel, 1)        self.padding = (kernel // 2, 1) if H else (1, kernel // 2)        self.group = group        self.pad = nn.ReflectionPad2d((pad, pad, 0, 0)) if H else nn.ReflectionPad2d((0, 0, pad, pad))        self.conv = nn.Conv2d(dim, group * kernel, kernel_size=1, stride=1, bias=False)        self.ap = nn.AdaptiveAvgPool2d((1, 1))        self.filter_act = nn.Sigmoid()    def forward(self, x):        filter = self.ap(x)        filter = self.conv(filter)        n, c, h, w = x.shape        x = F.unfold(self.pad(x), kernel_size=self.kernel).reshape(n, self.group, c // self.group, self.k, h * w)        n, c1, p, q = filter.shape        filter = filter.reshape(n, c1 // self.k, self.k, p * q).unsqueeze(2)        filter = self.filter_act(filter)        out = torch.sum(x * filter, dim=3).reshape(n, c, h, w)        return outif __name__ == "__main__":    # 模块参数    batch_size = 1  # 批大小    channels = 32  # 输入特征通道数    height = 256  # 图像高度    width = 256  # 图像宽度    # 创建 SSA 模块    ssa = SSA(dim=32, group=1, kernel=7)    print(ssa)    print("哔哩哔哩CV缝合救星, nice!")    # 生成随机输入张量 (batch_size, channels, height, width)    x = torch.randn(batch_size, channels, height, width)    # 打印输入张量的形状    print("Input shape:", x.shape)    # 前向传播计算输出    output = ssa(x)    # 打印输出张量的形状    print("Output shape:", output.shape)